if(window.innerWidth<=768){document.addEventListener('DOMContentLoaded',function(){var m=document.querySelector('.hero-bg__metrics');if(m)m.style.display='none';});}
const themeToggleButtons = document.querySelectorAll('.theme-toggle');
const themeStorageKey = 'nextiweb-theme';
const themeMediaQuery = window.matchMedia('(prefers-color-scheme: light)');
const cookieConsentStorageKey = 'nextiweb-cookie-consent-v1';
const currentPathname = window.location.pathname;
const isEnglishLocale = currentPathname === '/en' || currentPathname.startsWith('/en/');
function getLocalizedPath(pathname, targetLocale) {
const safePath = pathname || '/';
if (targetLocale === 'en') {
if (safePath === '/en' || safePath.startsWith('/en/')) {
return safePath === '/en' ? '/en/index.html' : safePath;
}
if (safePath === '/') {
return '/en/index.html';
}
return '/en' + safePath;
}
if (safePath === '/en') {
return '/';
}
if (safePath.startsWith('/en/')) {
const withoutPrefix = safePath.replace(/^\/en/, '');
if (withoutPrefix === '/index.html') {
return '/';
}
return withoutPrefix || '/';
}
return safePath;
}
function buildLocaleUrl(targetLocale) {
const localizedPath = getLocalizedPath(window.location.pathname, targetLocale);
return localizedPath + window.location.search + window.location.hash;
}
function rewriteInternalLinksForEnglish() {
document.querySelectorAll('a[href]').forEach((link) => {
const href = link.getAttribute('href');
if (!href || href.startsWith('#') || href.startsWith('mailto:') || href.startsWith('tel:')) {
return;
}
let resolvedUrl;
try {
resolvedUrl = new URL(href, window.location.origin);
} catch {
return;
}
if (resolvedUrl.origin !== window.location.origin) {
return;
}
resolvedUrl.pathname = getLocalizedPath(resolvedUrl.pathname, 'en');
link.setAttribute('href', resolvedUrl.pathname + resolvedUrl.search + resolvedUrl.hash);
});
}
function localizeGlobalUiToEnglish() {
document.documentElement.lang = 'en';
const nav = document.querySelector('.main-nav');
if (nav) {
nav.setAttribute('aria-label', 'Main navigation');
}
const mapByHref = {
'/services.html': 'Services',
'/creation-site.html': 'Website Design',
'/seo.html': 'SEO',
'/marketing-digital.html': 'Digital Marketing',
'/secteurs.html': 'Industries',
'/ressources.html': 'Resources',
'/a-propos.html': 'About',
'/contact.html': 'Get a free audit',
'/mentions-legales.html': 'Legal Notice',
'/politique-confidentialite.html': 'Privacy Policy',
'/politique-cookies.html': 'Cookie Policy',
'/zones-desservies/montreal.html': 'Montreal',
'/zones-desservies/quebec.html': 'Quebec',
'/zones-desservies/canada.html': 'Canada'
};
document.querySelectorAll('a[href]').forEach((link) => {
const href = link.getAttribute('href');
if (!href) {
return;
}
let resolvedUrl;
try {
resolvedUrl = new URL(href, window.location.origin);
} catch {
return;
}
const sourcePath = getLocalizedPath(resolvedUrl.pathname, 'fr');
const translatedLabel = mapByHref[sourcePath];
if (translatedLabel) {
link.textContent = translatedLabel;
}
});
document.querySelectorAll('.footer__title').forEach((title) => {
const cleanValue = title.textContent.trim();
if (cleanValue === 'Navigation') {
title.textContent = 'Navigation';
}
if (cleanValue === 'Services') {
title.textContent = 'Services';
}
if (cleanValue === 'Zones desservies') {
title.textContent = 'Covered Areas';
}
});
document.querySelectorAll('.footer__text').forEach((text) => {
const cleanValue = text.textContent.trim();
if (cleanValue.includes('Agence web spécialisée')) {
text.textContent = 'Web agency specialized in website design, SEO and digital marketing.';
}
});
}
function initializeLanguageSwitcher() {
const headerInner = document.querySelector('.header__inner');
if (!headerInner || headerInner.querySelector('.language-switcher')) {
return;
}
const switcher = document.createElement('div');
switcher.className = 'language-switcher';
switcher.setAttribute('role', 'group');
switcher.setAttribute('aria-label', isEnglishLocale ? 'Language selector' : 'Sélecteur de langue');
const frButton = document.createElement('button');
frButton.type = 'button';
frButton.className = 'language-switcher__btn' + (!isEnglishLocale ? ' is-active' : '');
frButton.textContent = 'FR';
frButton.setAttribute('aria-pressed', String(!isEnglishLocale));
const enButton = document.createElement('button');
enButton.type = 'button';
enButton.className = 'language-switcher__btn' + (isEnglishLocale ? ' is-active' : '');
enButton.textContent = 'EN';
enButton.setAttribute('aria-pressed', String(isEnglishLocale));
frButton.addEventListener('click', () => {
window.location.href = buildLocaleUrl('fr');
});
enButton.addEventListener('click', () => {
window.location.href = buildLocaleUrl('en');
});
switcher.appendChild(frButton);
switcher.appendChild(enButton);
const themeButton = headerInner.querySelector('.theme-toggle');
if (themeButton) {
headerInner.insertBefore(switcher, themeButton);
} else {
headerInner.appendChild(switcher);
}
}
if (isEnglishLocale) {
rewriteInternalLinksForEnglish();
localizeGlobalUiToEnglish();
}
initializeLanguageSwitcher();
function getStoredTheme() {
try {
const storedTheme = window.localStorage.getItem(themeStorageKey);
return storedTheme === 'theme-light' || storedTheme === 'theme-dark' ? storedTheme : null;
} catch {
return null;
}
}
function storeTheme(theme) {
try {
window.localStorage.setItem(themeStorageKey, theme);
} catch {
}
}
function getPreferredTheme() {
return getStoredTheme() || (themeMediaQuery.matches ? 'theme-light' : 'theme-dark');
}
function updateThemeButtons(theme) {
const isLightTheme = theme === 'theme-light';
const nextThemeLabel = isEnglishLocale
? (isLightTheme ? 'Enable dark mode' : 'Enable light mode')
: (isLightTheme ? 'Activer le mode sombre' : 'Activer le mode clair');
const currentThemeLabel = isEnglishLocale
? (isLightTheme ? 'Light mode' : 'Dark mode')
: (isLightTheme ? 'Mode clair' : 'Mode sombre');
const themeIcon = isLightTheme ? '☀' : '☾';
themeToggleButtons.forEach((button) => {
button.setAttribute('aria-label', nextThemeLabel);
button.setAttribute('aria-pressed', String(isLightTheme));
button.setAttribute('title', nextThemeLabel);
button.innerHTML = '<span class="theme-toggle__icon" aria-hidden="true">' + themeIcon + '</span><span class="theme-toggle__text">' + currentThemeLabel + '</span>';
});
}
function applyTheme(theme, shouldStoreTheme = true) {
document.body.classList.remove('theme-dark', 'theme-light');
document.body.classList.add(theme);
document.documentElement.style.colorScheme = theme === 'theme-light' ? 'light' : 'dark';
updateThemeButtons(theme);
const isLight = theme === 'theme-light';
document.querySelectorAll('.logo img').forEach(img => {
const base = img.src.substring(0, img.src.lastIndexOf('/') + 1);
img.src = base + (isLight ? 'logo-nextiweb-light.png' : 'logo-nextiweb-dark.png');
img.style.filter = '';
});
if (shouldStoreTheme) {
storeTheme(theme);
}
}
if (themeToggleButtons.length) {
applyTheme(getPreferredTheme(), false);
themeToggleButtons.forEach((button) => {
button.addEventListener('click', () => {
const nextTheme = document.body.classList.contains('theme-light') ? 'theme-dark' : 'theme-light';
applyTheme(nextTheme);
});
});
themeMediaQuery.addEventListener('change', (event) => {
if (!getStoredTheme()) {
applyTheme(event.matches ? 'theme-light' : 'theme-dark', false);
}
});
}
function sanitizeCookiePreferences(rawPreferences) {
const hasValidShape = rawPreferences && typeof rawPreferences === 'object';
if (!hasValidShape) {
return null;
}
const preferences = {
essential: true,
analytics: Boolean(rawPreferences.analytics),
marketing: Boolean(rawPreferences.marketing),
updatedAt: typeof rawPreferences.updatedAt === 'string' ? rawPreferences.updatedAt : new Date().toISOString()
};
return preferences;
}
function readCookiePreferences() {
try {
const storedValue = window.localStorage.getItem(cookieConsentStorageKey);
if (!storedValue) {
return null;
}
return sanitizeCookiePreferences(JSON.parse(storedValue));
} catch {
return null;
}
}
function saveCookiePreferences(preferences) {
try {
window.localStorage.setItem(cookieConsentStorageKey, JSON.stringify(preferences));
} catch {
}
}
function applyCookiePreferences(preferences) {
document.documentElement.dataset.cookieEssential = 'granted';
document.documentElement.dataset.cookieAnalytics = preferences.analytics ? 'granted' : 'denied';
document.documentElement.dataset.cookieMarketing = preferences.marketing ? 'granted' : 'denied';
window.dispatchEvent(new CustomEvent('nextiweb:cookie-consent-updated', {
detail: preferences
}));
}
function removeCookieBanner() {
const banner = document.getElementById('cookie-banner');
if (banner) {
banner.remove();
}
}
function setCookiePreferences(preferences) {
const normalizedPreferences = {
essential: true,
analytics: Boolean(preferences.analytics),
marketing: Boolean(preferences.marketing),
updatedAt: new Date().toISOString()
};
saveCookiePreferences(normalizedPreferences);
applyCookiePreferences(normalizedPreferences);
removeCookieBanner();
}
function injectLegalFooterLinks() {
document.querySelectorAll('.footer__bottom').forEach((footerBottom) => {
if (footerBottom.querySelector('.footer__legal')) {
return;
}
const legalParagraph = document.createElement('p');
legalParagraph.className = 'footer__legal';
if (isEnglishLocale) {
legalParagraph.innerHTML = 'Read our <a href="/en/politique-confidentialite.html">Privacy Policy</a>, <a href="/en/politique-cookies.html">Cookie Policy</a> and <a href="/en/mentions-legales.html">Legal Notice</a>. <button type="button" class="footer__legal-btn" data-open-cookie-settings>Manage cookies</button>';
} else {
legalParagraph.innerHTML = 'Consultez notre <a href="/politique-confidentialite.html">politique de confidentialité</a>, notre <a href="/politique-cookies.html">politique de cookies</a> et nos <a href="/mentions-legales.html">mentions légales</a>. <button type="button" class="footer__legal-btn" data-open-cookie-settings>Gérer mes cookies</button>';
}
footerBottom.appendChild(legalParagraph);
});
}
function createCookieBanner(initialPreferences = null) {
if (document.getElementById('cookie-banner')) {
return;
}
const preferences = initialPreferences || {
analytics: false,
marketing: false
};
const banner = document.createElement('div');
banner.id = 'cookie-banner';
banner.className = 'cookie-banner';
banner.setAttribute('role', 'dialog');
banner.setAttribute('aria-live', 'polite');
banner.setAttribute('aria-label', isEnglishLocale ? 'Cookie consent management' : 'Gestion du consentement aux cookies');
banner.innerHTML = isEnglishLocale
? [
'<div class="cookie-banner__content">',
'<h2 class="cookie-banner__title">Cookie preferences</h2>',
'<p class="cookie-banner__text">We use essential cookies to keep this site running. Analytics and marketing cookies are enabled only with your consent.</p>',
'<p class="cookie-banner__links"><a href="/en/politique-confidentialite.html">Privacy Policy</a> · <a href="/en/politique-cookies.html">Cookie Policy</a></p>',
'<div class="cookie-banner__actions">',
'<button type="button" class="btn btn--primary" data-cookie-action="accept-all">Accept all</button>',
'<button type="button" class="btn btn--ghost" data-cookie-action="reject-all">Reject all</button>',
'<button type="button" class="btn btn--ghost" data-cookie-action="toggle-settings">Customize</button>',
'</div>',
'<div class="cookie-banner__settings" hidden>',
'<label class="cookie-banner__option"><input type="checkbox" checked disabled> Essential cookies (required)</label>',
'<label class="cookie-banner__option"><input type="checkbox" data-cookie-option="analytics"> Analytics cookies</label>',
'<label class="cookie-banner__option"><input type="checkbox" data-cookie-option="marketing"> Marketing cookies</label>',
'<div class="cookie-banner__actions cookie-banner__actions--inline">',
'<button type="button" class="btn btn--primary" data-cookie-action="save-settings">Save my choices</button>',
'</div>',
'</div>',
'</div>'
].join('')
: [
'<div class="cookie-banner__content">',
'<h2 class="cookie-banner__title">Gestion des cookies</h2>',
'<p class="cookie-banner__text">Nous utilisons des cookies essentiels pour le fonctionnement du site. Les cookies de mesure et de marketing ne sont activés qu\'avec votre consentement, conformément à la Loi 25.</p>',
'<p class="cookie-banner__links"><a href="/politique-confidentialite.html">Politique de confidentialité</a> · <a href="/politique-cookies.html">Politique de cookies</a></p>',
'<div class="cookie-banner__actions">',
'<button type="button" class="btn btn--primary" data-cookie-action="accept-all">Accepter tout</button>',
'<button type="button" class="btn btn--ghost" data-cookie-action="reject-all">Refuser</button>',
'<button type="button" class="btn btn--ghost" data-cookie-action="toggle-settings">Personnaliser</button>',
'</div>',
'<div class="cookie-banner__settings" hidden>',
'<label class="cookie-banner__option"><input type="checkbox" checked disabled> Cookies essentiels (obligatoires)</label>',
'<label class="cookie-banner__option"><input type="checkbox" data-cookie-option="analytics"> Cookies de mesure d\'audience</label>',
'<label class="cookie-banner__option"><input type="checkbox" data-cookie-option="marketing"> Cookies marketing</label>',
'<div class="cookie-banner__actions cookie-banner__actions--inline">',
'<button type="button" class="btn btn--primary" data-cookie-action="save-settings">Enregistrer mes choix</button>',
'</div>',
'</div>',
'</div>'
].join('');
document.body.appendChild(banner);
const analyticsInput = banner.querySelector('[data-cookie-option="analytics"]');
const marketingInput = banner.querySelector('[data-cookie-option="marketing"]');
const settingsPanel = banner.querySelector('.cookie-banner__settings');
if (analyticsInput) {
analyticsInput.checked = Boolean(preferences.analytics);
}
if (marketingInput) {
marketingInput.checked = Boolean(preferences.marketing);
}
banner.addEventListener('click', (event) => {
const actionButton = event.target.closest('[data-cookie-action]');
if (!actionButton) {
return;
}
const action = actionButton.getAttribute('data-cookie-action');
if (action === 'accept-all') {
setCookiePreferences({ analytics: true, marketing: true });
return;
}
if (action === 'reject-all') {
setCookiePreferences({ analytics: false, marketing: false });
return;
}
if (action === 'toggle-settings') {
const shouldOpen = settingsPanel.hidden;
settingsPanel.hidden = !shouldOpen;
return;
}
if (action === 'save-settings') {
setCookiePreferences({
analytics: Boolean(analyticsInput?.checked),
marketing: Boolean(marketingInput?.checked)
});
}
});
}
function initializeCookieConsent() {
injectLegalFooterLinks();
const storedPreferences = readCookiePreferences();
if (storedPreferences) {
applyCookiePreferences(storedPreferences);
} else {
applyCookiePreferences({ essential: true, analytics: false, marketing: false });
createCookieBanner();
}
document.addEventListener('click', (event) => {
const trigger = event.target.closest('[data-open-cookie-settings]');
if (!trigger) {
return;
}
event.preventDefault();
const currentPreferences = readCookiePreferences() || { analytics: false, marketing: false };
createCookieBanner(currentPreferences);
const settingsPanel = document.querySelector('#cookie-banner .cookie-banner__settings');
if (settingsPanel) {
settingsPanel.hidden = false;
}
});
}
initializeCookieConsent();
