(function(){var topBar=document.querySelector('.top-bar'),header=document.querySelector('.site-header');function setLayout(){var tbH=topBar?topBar.offsetHeight:0,hH=header?header.offsetHeight:0;if(header)header.style.top=tbH+'px';var s=document.getElementById('nw-layout-pad');if(!s){s=document.createElement('style');s.id='nw-layout-pad';document.head.appendChild(s);}s.textContent='body{padding-top:'+(tbH+hH)+'px!important}';}function onScroll(){if(window.scrollY>60){document.body.classList.add('scrolled');if(header)header.style.top='0';}else{document.body.classList.remove('scrolled');setLayout();}}setLayout();window.addEventListener('load',setLayout);window.addEventListener('resize',setLayout,{passive:true});window.addEventListener('scroll',onScroll,{passive:true});})();
